import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { icon } from 'decantr/components';

code.example:
function LogoStrip({ logos }) {
  const { div, span, img } = tags;

  return div({ class: css('_flex _col _aic _gap4 _py8') },
    span({ class: css('_textxs _fgmuted _uppercase _tracking[0.1em]') }, 'Trusted by teams at'),
    div({ class: css('_flex _aic _jcc _gap8 _wrap') },
      ...logos.map(l =>
        img({ src: l.src, alt: l.name, class: css('_h[24px] _fgmuted _opacity[0.5] _h:opacity[1] _trans[opacity_0.2s_ease]') })
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Marquee } from 'decantr/components';

code.example:
function LogoMarquee({ logos }) {
  const { div, span, img } = tags;
  const half = Math.ceil(logos.length / 2);
  const row1 = logos.slice(0, half);
  const row2 = logos.slice(half);

  return div({ class: css('_flex _col _aic _gap4 _py8') },
    span({ class: css('_textxs _fgmuted _uppercase _tracking[0.1em]') }, 'Trusted by teams worldwide'),
    Marquee({ speed: 35, gap: 8 },
      ...row1.map(l => img({ src: l.src, alt: l.name, class: css('_h[24px] _fgmuted _opacity[0.5]') }))
    ),
    Marquee({ speed: 35, direction: 'right', gap: 8 },
      ...row2.map(l => img({ src: l.src, alt: l.name, class: css('_h[24px] _fgmuted _opacity[0.5]') }))
    )
  );
}

